import React, { useState, useEffect, useContext } from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  MenuItem,
  TextField,
  CircularProgress,
  Divider,
} from '@mui/material';
import axios from 'axios';
import { API_URL } from '../utils/apiUrl';
import { AuthContext } from '../context/AuthContext';

export default function SalesReport() {
  const { user } = useContext(AuthContext);
  const [outlets, setOutlets] = useState([]);
  const [selectedOutlet, setSelectedOutlet] = useState('all');
  const [reportData, setReportData] = useState([]); // Array হিসেবে রাখছি কারণ 'all' এ লিস্ট আসবে
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (user) {
      const isAdmin =
        user.role?.name === 'SUPERADMIN' || user.role?.name === 'ADMIN';
      const initialOutlet = isAdmin ? 'all' : user.outlet_id;
      setSelectedOutlet(initialOutlet);

      if (isAdmin) {
        axios
          .get(`${API_URL}/api/outlets`)
          .then((res) => setOutlets(res.data.data || []));
      }
    }
  }, [user]);

  const fetchReport = async () => {
    try {
      setLoading(true);
      let url =
        selectedOutlet === 'all'
          ? `${API_URL}/api/reports/outlets`
          : `${API_URL}/api/reports/outlets/${selectedOutlet}`;

      const response = await axios.get(url);

      // API থেকে আসা ডাটা সেট করা
      // আপনার API 'data' কি এর ভেতর লিস্ট পাঠাচ্ছে, তাই response.data.data নিচ্ছি
      setReportData(response.data.data || []);
    } catch (error) {
      console.error('Report Error:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (selectedOutlet) fetchReport();
  }, [selectedOutlet]);

  return (
    <Box sx={{ p: 3 }}>
      <Box
        sx={{
          display: 'flex',
          justifyContent: 'space-between',
          mb: 3,
          alignItems: 'center',
        }}
      >
        <Typography variant="h4" fontWeight="bold">
          {selectedOutlet === 'all'
            ? '🌍 Global Sales Report'
            : '🏪 Outlet Specific Report'}
        </Typography>

        {(user?.role?.name === 'SUPERADMIN' ||
          user?.role?.name === 'ADMIN') && (
          <TextField
            select
            size="small"
            label="Select Outlet"
            value={selectedOutlet}
            onChange={(e) => setSelectedOutlet(e.target.value)}
            sx={{ minWidth: 200 }}
          >
            <MenuItem value="all">All Outlets (Combined)</MenuItem>
            {outlets.map((o) => (
              <MenuItem key={o.id} value={o.id}>
                {o.name}
              </MenuItem>
            ))}
          </TextField>
        )}
      </Box>

      {loading ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', mt: 5 }}>
          <CircularProgress />
        </Box>
      ) : (
        <Grid container spacing={3}>
          {/* যদি 'all' সিলেক্ট থাকে, তবে প্রতিটি আউটলেটের জন্য আলাদা কার্ড দেখাবে */}
          {selectedOutlet === 'all' ? (
            reportData.map((outletReport) => (
              <Grid item xs={12} key={outletReport.outlet_id}>
                <Card
                  variant="outlined"
                  sx={{ mb: 2, borderLeft: '6px solid #1976d2' }}
                >
                  <CardContent>
                    <Box
                      sx={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        mb: 2,
                      }}
                    >
                      <Typography
                        variant="h5"
                        color="primary"
                        fontWeight="bold"
                      >
                        🏪 {outletReport.outlet_name}
                      </Typography>
                      <Box sx={{ textAlign: 'right' }}>
                        <Typography variant="body2" color="text.secondary">
                          Total Revenue
                        </Typography>
                        <Typography variant="h5" fontWeight="bold">
                          ৳{outletReport.total_revenue}
                        </Typography>
                      </Box>
                    </Box>

                    <Divider sx={{ mb: 2 }} />

                    <Typography
                      variant="subtitle1"
                      fontWeight="bold"
                      gutterBottom
                    >
                      🔥 Top 5 Items in this Outlet
                    </Typography>
                    <Table size="small">
                      <TableHead sx={{ bgcolor: '#f9f9f9' }}>
                        <TableRow>
                          <TableCell>Product</TableCell>
                          <TableCell align="right">Qty Sold</TableCell>
                          <TableCell align="right">Revenue</TableCell>
                        </TableRow>
                      </TableHead>
                      <TableBody>
                        {outletReport.top_5_items?.map((item, i) => (
                          <TableRow key={i}>
                            <TableCell>{item.product_name}</TableCell>
                            <TableCell align="right">
                              {item.total_qty_sold}
                            </TableCell>
                            <TableCell align="right">
                              ৳{item.total_revenue}
                            </TableCell>
                          </TableRow>
                        ))}
                        {outletReport.top_5_items?.length === 0 && (
                          <TableRow>
                            <TableCell colSpan={3} align="center">
                              No sales yet
                            </TableCell>
                          </TableRow>
                        )}
                      </TableBody>
                    </Table>
                  </CardContent>
                </Card>
              </Grid>
            ))
          ) : (
            /* নির্দিষ্ট একটা আউটলেটের ডাটা দেখানোর জন্য (সিঙ্গেল ভিউ) */
            <Grid item xs={12}>
              {/* এখানে আপনি আগের মতো সিঙ্গেল আউটলেটের ডাটা দেখাতে পারেন */}
              <Typography>Showing report for single outlet...</Typography>
              {/* reportData[0] বা সরাসরি ডাটা অবজেক্ট ব্যবহার করুন */}
            </Grid>
          )}
        </Grid>
      )}
    </Box>
  );
}
